parameters.jsCode:
let raw = $input.item.json.output || '';
raw = raw.replace(/```json/g, '').replace(/```/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  // fail safe toward caution if the model ever returns malformed JSON
  parsed = { is_crisis: false, is_medical_request: false, urgency: 'low' };
}

return [{ json: parsed }];

